/usr/bin/bash -lc "python3 - <<'PY'
import json, glob, re
pat=re.compile('economic development adviser|economic adviser|development adviser|Pritzker|Jaresko|Abromavicius|Kubrakov|Budanov',re.I)
for path in sorted(glob.glob('articles/2026/01/02/articles.jsonl')):
    for line in open(path):
        a=json.loads(line)
        if a.get('date_publish','') > '2026-01-02':
            continue
        txt=(a.get('title') or '')+' '+(a.get('content') or '')
        if pat.search(txt):
            print('\\n###',a.get('date_publish'),a.get('source'),a.get('title'))
            content=(a.get('content') or '').replace('\\n',' ')
            m=pat.search(content) or pat.search(a.get('title') or '')
            if m:
                print(content[max(0,m.start()-500):m.end()+2000][:3000])
            else:
                print(content[:2000])
PY"

